24: /**
25:  * Makes a real HTTP request to the given path with optional headers.
26:  * No mocks - all HTTP layer interactions are real.
27:  * This is the integration boundary the claim depends on.
28:  */
29: function makeRequest(path: string, headers: Record<string, string> = {}, method: string = 'GET'): Promise<{
30:   statusCode: number;
31:   headers: http.IncomingHttpHeaders;
32:   body: string;
33:   error?: string;
34: }> {
35:   return new Promise((resolve) => {
36:     const url = new URL(path, BASE_URL);
37:     const options: http.RequestOptions = {
38:       hostname: url.hostname,
39:       port: url.port,
40:       path: url.pathname,
41:       method: method,
42:       headers: headers
43:     };
44: 
45:     const req = http.request(options, (res) => {
46:       let body = '';
47:       res.on('data', (chunk: Buffer) => body += chunk.toString());
48:       res.on('end', () => {
49:         resolve({
50:           statusCode: res.statusCode || 0,
51:           headers: res.headers,
52:           body: body
53:         });
54:       });
55:     });
56: 
57:     req.on('error', (err: NodeJS.ErrnoException) => {
58:       // Connection refused means server not running - this is expected in red-phase
59:       if (err.code === 'ECONNREFUSED') {
60:         resolve({ statusCode: 0, headers: {}, body: '', error: 'SERVER_NOT_RUNNING' });
61:       } else {
62:         resolve({ statusCode: 0, headers: {}, body: '', error: err.message });
63:       }
64:     });
65: 
66:     req.end();
67:   });
68: }
